use anyhow::{Context, Result};
use clap::Args;
use iris_agentic_dev_core::iris::connection::CompileResult;
use iris_agentic_dev_core::iris::{
    connection::{DiscoverySource, IrisConnection},
    discovery::{discover_iris, IrisDiscovery},
};

#[derive(Args)]
pub struct CompileCommand {
    pub target: Option<String>,
    #[arg(long, env = "IRIS_HOST")]
    pub host: Option<String>,
    #[arg(long, env = "IRIS_WEB_PORT", default_value = "52773")]
    pub web_port: u16,
    #[arg(long, env = "IRIS_NAMESPACE", default_value = "USER")]
    pub namespace: String,
    #[arg(long, env = "IRIS_USERNAME")]
    pub username: Option<String>,
    #[arg(long, env = "IRIS_PASSWORD")]
    pub password: Option<String>,
    #[arg(long, default_value = "cuk")]
    pub flags: String,
    #[arg(long)]
    pub force_writable: bool,
    #[arg(long, default_value = "text")]
    pub format: String,
}

impl CompileCommand {
    pub async fn run(self) -> Result<()> {
        let explicit = self.host.as_ref().map(|host| {
            let base_url = format!("http://{}:{}", host, self.web_port);
            let username = self.username.as_deref().unwrap_or("_SYSTEM");
            let password = self.password.as_deref().unwrap_or("SYS");
            IrisConnection::new(
                base_url,
                &self.namespace,
                username,
                password,
                DiscoverySource::ExplicitFlag,
            )
        });

        // Load .iris-agentic-dev.toml — takes precedence over env vars but not CLI flags (FR-006, FR-007).
        let ws_path = std::env::var("OBJECTSCRIPT_WORKSPACE").ok();
        let explicit = iris_agentic_dev_core::iris::workspace_config::apply_workspace_config(
            explicit,
            ws_path.as_deref(),
            &self.namespace,
        );

        let iris = match discover_iris(explicit).await {
            IrisDiscovery::Found(c) => c,
            IrisDiscovery::NotFound => {
                anyhow::bail!(
                    "No IRIS connection found — set IRIS_HOST or run iris-agentic-dev mcp for auto-discovery"
                );
            }
            IrisDiscovery::Explained => {
                // Specific actionable message already emitted to stderr — exit cleanly.
                std::process::exit(1);
            }
        };

        let client = IrisConnection::http_client()?;
        let target = self.target.as_deref().unwrap_or(".");

        // ── .cls file: upload via Atelier PUT then compile via /action/compile ──
        if target.ends_with(".cls") {
            let cls_text =
                std::fs::read_to_string(target).with_context(|| format!("reading {}", target))?;
            let cls_name = cls_text
                .lines()
                .find(|l| l.trim_start().starts_with("Class "))
                .and_then(|l| l.split_whitespace().nth(1))
                .map(|s| s.to_string())
                .unwrap_or_else(|| {
                    target
                        .trim_end_matches(".cls")
                        .replace(['/', '\\'], ".")
                        .trim_start_matches('.')
                        .to_string()
                });
            let doc_name = format!("{}.cls", cls_name);

            // Upload
            let put_url = iris.versioned_ns_url(
                &self.namespace,
                &format!("/doc/{}?ignoreConflict=1", urlencoding::encode(&doc_name)),
            );
            let lines: Vec<&str> = cls_text.lines().collect();
            let put_resp = client
                .put(&put_url)
                .basic_auth(&iris.username, Some(&iris.password))
                .json(&serde_json::json!({"enc": false, "content": lines}))
                .send()
                .await
                .context("PUT /doc failed")?;
            if !put_resp.status().is_success() {
                anyhow::bail!("Upload failed: HTTP {}", put_resp.status());
            }
            let put_body: serde_json::Value = put_resp.json().await.unwrap_or_default();
            if let Some(errs) = put_body["status"]["errors"].as_array() {
                if !errs.is_empty() {
                    let msg = errs[0]["error"].as_str().unwrap_or("Upload failed");
                    let result = serde_json::json!({"success": false, "error_code": "UPLOAD_FAILED", "error": msg, "target": target});
                    output_result(&result, &self.format);
                    std::process::exit(1);
                }
            }

            // Compile via /action/compile (structured errors, line numbers)
            let compile_result = iris
                .compile_document(&doc_name, &self.namespace, &self.flags, &client)
                .await
                .context("compile request failed")?;
            let result = compile_result_to_json(&compile_result, target, &self.namespace);
            output_result(&result, &self.format);
            if !compile_result.success() {
                std::process::exit(1);
            }
            return Ok(());
        }

        // ── non-.cls target: compile by name via /action/compile ──
        let doc_name = if target == "." {
            // CompileAll — use a special marker; handled below
            target.to_string()
        } else {
            target.to_string()
        };

        if doc_name == "." {
            // CompileAll via ObjectScript (no Atelier endpoint for this)
            let code = format!(
                "Set sc=$SYSTEM.OBJ.CompileAll(\"{}\") If $System.Status.IsOK(sc) {{Write \"OK\"}} Else {{Write $System.Status.GetErrorText(sc)}}",
                self.flags
            );
            let out = iris
                .execute_via_generator(&code, &self.namespace, &client)
                .await
                .context("CompileAll failed")?;
            let out = out.trim();
            if out.ends_with("OK") || out == "OK" {
                let result = serde_json::json!({"success": true, "target": ".", "namespace": self.namespace});
                output_result(&result, &self.format);
            } else {
                let result = serde_json::json!({"success": false, "error_code": "IRIS_COMPILE_FAILED", "error": out, "target": "."});
                output_result(&result, &self.format);
                std::process::exit(1);
            }
        } else {
            let compile_result = iris
                .compile_document(&doc_name, &self.namespace, &self.flags, &client)
                .await
                .context("compile request failed")?;
            let result = compile_result_to_json(&compile_result, target, &self.namespace);
            output_result(&result, &self.format);
            if !compile_result.success() {
                std::process::exit(1);
            }
        }
        Ok(())
    }
}

fn compile_result_to_json(r: &CompileResult, target: &str, namespace: &str) -> serde_json::Value {
    let errors: Vec<serde_json::Value> = r
        .errors
        .iter()
        .map(|e| serde_json::json!({"severity":"error","text":e}))
        .collect();
    serde_json::json!({
        "success": r.success(),
        "target": target,
        "namespace": namespace,
        "errors": errors,
        "console": r.console,
    })
}

fn output_result(result: &serde_json::Value, format: &str) {
    if format == "json" {
        println!("{}", result);
    } else if result["success"] == true {
        println!("✓ Compiled: {}", result["target"].as_str().unwrap_or(""));
    } else {
        eprintln!(
            "✗ Error [{}]: {}",
            result["error_code"].as_str().unwrap_or(""),
            result["error"].as_str().unwrap_or("")
        );
    }
}

use anyhow::{Context, Result};
use clap::Args;

#[derive(Args)]
pub struct InitCommand {
    /// Overwrite existing .iris-agentic-dev.toml if present
    #[arg(long)]
    pub force: bool,
    /// Workspace directory (default: current directory)
    #[arg(long, default_value = ".")]
    pub workspace: String,
    /// Output format: text or json
    #[arg(long, default_value = "text")]
    pub format: String,
}

impl InitCommand {
    pub async fn run(self) -> Result<()> {
        let workspace = std::path::Path::new(&self.workspace);
        let config_path = workspace.join(".iris-agentic-dev.toml");

        if config_path.exists() && !self.force {
            anyhow::bail!(
                ".iris-agentic-dev.toml already exists at {}. Use --force to overwrite.",
                config_path.display()
            );
        }

        // Detect best-matching container using workspace basename scoring
        let workspace_basename = workspace
            .canonicalize()
            .unwrap_or_else(|_| workspace.to_path_buf())
            .file_name()
            .and_then(|n| n.to_str())
            .unwrap_or("project")
            .to_string();

        let containers =
            iris_agentic_dev_core::tools::list_iris_containers_pub(&workspace_basename).await;
        if containers.is_empty() {
            eprintln!(
                "⚠ No running IRIS containers found. If your container was started without \
                 IRIS_PASSWORD, restart with: docker run -e IRIS_PASSWORD=SYS ..."
            );
        }
        let suggested_container = containers
            .first()
            .and_then(|c| c["name"].as_str())
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("{}-iris", workspace_basename));

        let content = iris_agentic_dev_core::iris::workspace_config::generate_toml_content(
            &suggested_container,
            "USER",
        );

        std::fs::write(&config_path, &content)
            .with_context(|| format!("writing {}", config_path.display()))?;

        if self.format == "json" {
            println!(
                "{}",
                serde_json::json!({
                    "success": true,
                    "path": config_path.to_string_lossy(),
                    "container": suggested_container,
                })
            );
        } else {
            println!("✓ Created {}", config_path.display());
            println!("  container = \"{}\"", suggested_container);
            println!("  namespace = \"USER\"");
        }
        Ok(())
    }
}

use anyhow::{Context, Result};
use clap::Args;
use iris_agentic_dev_core::manifest::{parse_manifest, Resolve};

#[derive(Args)]
pub struct InstallCommand {
    #[arg(long)]
    pub locked: bool,
    #[arg(long)]
    pub dry_run: bool,
}

impl InstallCommand {
    pub async fn run(self) -> Result<()> {
        let manifest_path = std::path::PathBuf::from("iris-agentic-dev.toml");
        let manifest = parse_manifest(&manifest_path).context(
            "could not read iris-agentic-dev.toml — run this command in a directory with an iris-agentic-dev.toml",
        )?;

        println!("Resolving {} dependencies...", manifest.dependencies.len());

        let resolve = Resolve::from_manifest(&manifest).context("dependency resolution failed")?;

        let lock = resolve.to_lock();

        if self.dry_run {
            println!("Would install {} packages:", lock.packages.len());
            for pkg in &lock.packages {
                println!("  {} v{} ({})", pkg.name, pkg.version, pkg.repository);
            }
            return Ok(());
        }

        let lock_content = lock.to_toml();
        std::fs::write("iris-agentic-dev.lock", &lock_content)
            .context("failed to write iris-agentic-dev.lock")?;

        println!(
            "Wrote iris-agentic-dev.lock with {} packages",
            lock.packages.len()
        );
        for pkg in &lock.packages {
            println!("  ✓ {} v{}", pkg.name, pkg.version);
        }

        Ok(())
    }
}

use anyhow::Result;
use clap::Args;
use iris_agentic_dev_core::{
    iris::discovery::{discover_iris, IrisDiscovery},
    skills::SkillRegistry,
    tools::{ConfigWatcher, IrisTools, Toolset},
};
use rmcp::{transport::stdio, ServiceExt};
use tokio::sync::watch;

/// Start the iris-dev MCP server (stdio transport by default).
///
/// REQUIREMENTS
///   IRIS must have the Atelier REST API enabled. Three ways to achieve this:
///
///   1. Community images (include private web server):
///      iris-community, irishealth-community → port 52773
///
///   2. Enterprise images + ISC Web Gateway container (recommended for production):
///      Use containers.intersystems.com/intersystems/webgateway alongside
///      intersystems/iris. The webgateway container exposes port 80/443 and
///      proxies Atelier REST. Set IRIS_WEB_PORT=<webgateway-host-port>.
///      iris-dev auto-detects webgateway containers in the Docker scan.
///
///   3. Enterprise images standalone: no private web server — requires option 2 above.
///
/// WEBGATEWAY SETUP GOTCHAS (verified 2026-05-03)
///   Three non-obvious bugs in fresh enterprise container + webgateway setups:
///   a) CSP.ini race: patch CSP.ini only after "Configuration_Initialized" appears in it
///   b) Missing credentials: add Username=_SYSTEM + Password=SYS to [LOCAL] in CSP.ini
///      (default tries CSPSystem which doesn't exist in fresh enterprise containers)
///   c) Wrong Apache directive: use "CSP On" in <Location />, not "SetHandler csp-handler-sa"
///   d) Expired password: run UnExpireUserPasswords("*") in %SYS on first start
///   See: https://github.com/intersystems-community/iris-dev/blob/master/light-skills/skills/iris-vscode-objectscript/SKILL.md
///
/// CONNECTION DISCOVERY (in priority order)
///   1. --host / IRIS_HOST env var
///   2. .iris-agentic-dev.toml in workspace (walks up from cwd)
///   3. IRIS_CONTAINER env var → Docker named container lookup
///   4. Localhost port scan (52773, 41773, 51773, 8080)
///   5. Auto-scan running Docker containers
#[derive(Args)]
pub struct McpCommand {
    #[arg(long, default_value = "stdio")]
    pub transport: String,
    #[arg(long, default_value = "8080")]
    pub port: u16,
    #[arg(long, env = "IRIS_HOST")]
    pub host: Option<String>,
    #[arg(long, env = "IRIS_WEB_PORT")]
    pub web_port: Option<u16>,
    #[arg(long, env = "IRIS_WEB_PREFIX", default_value = "")]
    pub web_prefix: String,
    /// URL scheme: http or https (default: http)
    #[arg(long, env = "IRIS_SCHEME", default_value = "http")]
    pub scheme: String,
    #[arg(long, env = "IRIS_USERNAME")]
    pub username: Option<String>,
    #[arg(long, env = "IRIS_PASSWORD")]
    pub password: Option<String>,
    #[arg(long, env = "IRIS_NAMESPACE", default_value = "USER")]
    pub namespace: String,
    #[arg(long)]
    pub server: Option<String>,
    #[arg(long)]
    pub config: Option<String>,
    #[arg(long = "subscribe")]
    pub subscribe: Vec<String>,
    #[arg(long, default_value = ".")]
    pub workspace: String,
    /// Tool set to register: baseline (all 34 tools), nostub (stubs removed),
    /// or merged (stubs removed + consolidated tools). Also read from IRIS_TOOLSET env var.
    #[arg(long, env = "IRIS_TOOLSET", default_value = "merged")]
    pub toolset: String,
}

impl McpCommand {
    pub async fn run(self) -> Result<()> {
        let toolset = Toolset::from_str(&self.toolset);
        tracing::info!(
            "iris-agentic-dev mcp starting — toolset={}",
            toolset.as_str()
        );

        let explicit = if let Some(host) = self.host.clone() {
            use iris_agentic_dev_core::iris::connection::{DiscoverySource, IrisConnection};
            let port = self.web_port.unwrap_or(52773);
            let prefix = self.web_prefix.trim_matches('/');
            let scheme = self.scheme.trim_matches('/');
            let base_url = if prefix.is_empty() {
                format!("{}://{}:{}", scheme, host, port)
            } else {
                format!("{}://{}:{}/{}", scheme, host, port, prefix)
            };
            let username = self.username.as_deref().unwrap_or("_SYSTEM");
            let password = self.password.as_deref().unwrap_or("SYS");
            Some(IrisConnection::new(
                base_url,
                &self.namespace,
                username,
                password,
                DiscoverySource::ExplicitFlag,
            ))
        } else {
            None
        };

        let (iris_tx, iris_rx) =
            watch::channel::<Option<iris_agentic_dev_core::iris::connection::IrisConnection>>(None);

        // Load .iris-agentic-dev.toml — takes precedence over env vars but not CLI flags (FR-006).
        // If --workspace was explicitly passed (not the default "."), warn when no config found.
        let ws_root =
            iris_agentic_dev_core::iris::workspace_config::workspace_root(Some(&self.workspace));
        if self.workspace != "." && !ws_root.join(".iris-agentic-dev.toml").exists() {
            tracing::warn!(
                "No .iris-agentic-dev.toml found at {} — falling back to auto-discovery. \
                 Set IRIS_HOST or IRIS_CONTAINER to connect directly.",
                ws_root.display()
            );
        }
        let explicit = iris_agentic_dev_core::iris::workspace_config::apply_workspace_config(
            explicit,
            Some(&self.workspace),
            &self.namespace,
        );

        tokio::spawn(async move {
            let conn = match discover_iris(explicit).await {
                IrisDiscovery::Found(c) => {
                    tracing::info!(
                        "IRIS connected: {}/api/atelier/{} {}",
                        c.base_url,
                        c.atelier_version.version_str(),
                        c.version.as_deref().unwrap_or("?")
                    );
                    Some(c)
                }
                IrisDiscovery::NotFound => {
                    tracing::warn!("No IRIS connection — tools return IRIS_UNREACHABLE");
                    None
                }
                IrisDiscovery::Explained => {
                    // Specific actionable message already emitted — add no noise.
                    None
                }
            };
            let _ = iris_tx.send(conn);
        });

        let mut registry = SkillRegistry::new();
        for owner_repo in &self.subscribe {
            match registry.load_from_github(owner_repo).await {
                Ok(()) => tracing::info!("Subscribed to {}", owner_repo),
                Err(e) => tracing::warn!("Failed to subscribe to {}: {}", owner_repo, e),
            }
        }

        // Wait briefly for discovery — env-var discovery (single HTTP probe) completes in <500ms.
        // Cap at 2s so Claude Code / Copilot get the initialize response well within their timeout.
        // Docker/localhost-scan discovery may still be running when tools are first called;
        // those return IRIS_UNREACHABLE and the client can retry.
        let mut iris_rx_wait = iris_rx.clone();
        let _ = tokio::time::timeout(
            tokio::time::Duration::from_secs(2),
            iris_rx_wait.wait_for(|v| v.is_some()),
        )
        .await;
        let iris = iris_rx.borrow().clone();

        // On Windows, stdout opens in text mode which translates \n → \r\n.
        // MCP clients expect bare \n-terminated JSON lines — set stdout/stdin to binary mode.
        #[cfg(windows)]
        unsafe {
            extern "C" {
                fn _setmode(fd: i32, mode: i32) -> i32;
            }
            const O_BINARY: i32 = 0x8000;
            _setmode(0, O_BINARY); // stdin
            _setmode(1, O_BINARY); // stdout
        }

        // Build ConfigWatcher for .iris-agentic-dev.toml hot-reload (034-live-connection-reload).
        let config_watcher = ConfigWatcher::new(ws_root.join(".iris-agentic-dev.toml"));
        let tools = IrisTools::with_registry_and_toolset(iris, registry, toolset, config_watcher)?;

        // FR-007: periodically sweep expired elicitation entries.
        {
            let store = tools.elicitation_store.clone();
            tokio::spawn(async move {
                loop {
                    tokio::time::sleep(std::time::Duration::from_secs(60)).await;
                    store.sweep();
                }
            });
        }

        let service = tools
            .serve(stdio())
            .await
            .inspect_err(|e| tracing::error!("MCP server error: {:?}", e))?;
        service.waiting().await?;
        Ok(())
    }
}

pub mod compile;
pub mod init;
pub mod install;
pub mod mcp;
pub mod plugin;

use anyhow::Result;

/// List all iris-agentic-dev-* binaries discovered on PATH.
pub fn list_plugins() {
    let prefix = "iris-agentic-dev-";
    let paths = std::env::var("PATH").unwrap_or_default();
    let mut plugins = vec![];
    for dir in std::env::split_paths(&paths) {
        if let Ok(entries) = std::fs::read_dir(&dir) {
            for entry in entries.flatten() {
                let name = entry.file_name().to_string_lossy().to_string();
                if let Some(cmd) = name.strip_prefix(prefix) {
                    plugins.push((cmd.to_string(), entry.path()));
                }
            }
        }
    }
    plugins.sort();
    plugins.dedup_by_key(|(name, _)| name.clone());
    if plugins.is_empty() {
        println!("No iris-agentic-dev-* plugins found on PATH.");
    } else {
        println!("Discovered plugins:");
        for (name, path) in plugins {
            println!("  {} → {}", name, path.display());
        }
    }
}

/// If a binary named iris-agentic-dev-{cmd} exists on PATH, exec it with the remaining args.
/// Never returns on Unix (process is replaced). Returns Ok on Windows after child exits.
pub fn try_dispatch_plugin(cmd: &str, args: &[String]) -> Result<()> {
    let binary = format!("iris-agentic-dev-{}", cmd);
    match which::which(&binary) {
        Ok(path) => {
            #[cfg(unix)]
            {
                use std::os::unix::process::CommandExt;
                let err = std::process::Command::new(&path).args(args).exec();
                anyhow::bail!("failed to exec {}: {}", path.display(), err);
            }
            #[cfg(not(unix))]
            {
                let status = std::process::Command::new(&path).args(args).status()?;
                std::process::exit(status.code().unwrap_or(1));
            }
        }
        Err(_) => {
            eprintln!(
                "iris-agentic-dev: unknown command '{}'\nRun `iris-agentic-dev --help` for available commands.",
                cmd
            );
            std::process::exit(1);
        }
    }
}

use anyhow::Result;
use clap::{Parser, Subcommand};
use tracing_subscriber::EnvFilter;

mod cmd;

#[derive(Parser)]
#[command(
    name = "iris-agentic-dev",
    version,
    about = "CLI and package manager for InterSystems IRIS developer ecosystem",
    long_about = None,
)]
struct Cli {
    #[command(subcommand)]
    command: Option<Commands>,

    /// Enable debug logging
    #[arg(long, global = true)]
    verbose: bool,

    /// List discovered iris-agentic-dev-* plugin commands on PATH
    #[arg(long)]
    list_plugins: bool,
}

#[derive(Subcommand)]
enum Commands {
    /// Start the MCP server (stdio or HTTP transport)
    Mcp(cmd::mcp::McpCommand),
    /// Compile ObjectScript .cls files on IRIS
    Compile(cmd::compile::CompileCommand),
    /// Initialize a .iris-dev.toml workspace config
    Init(cmd::init::InitCommand),
    /// Install packages from iris-dev.toml
    Install(cmd::install::InstallCommand),
}

#[tokio::main]
async fn main() -> Result<()> {
    let cli = Cli::parse();

    tracing_subscriber::fmt()
        .with_env_filter(EnvFilter::from_default_env().add_directive(if cli.verbose {
            tracing::Level::DEBUG.into()
        } else {
            tracing::Level::WARN.into()
        }))
        .with_writer(std::io::stderr)
        .with_ansi(false)
        .init();

    if cli.list_plugins {
        cmd::plugin::list_plugins();
        return Ok(());
    }

    match cli.command {
        Some(Commands::Mcp(cmd)) => cmd.run().await,
        Some(Commands::Compile(cmd)) => cmd.run().await,
        Some(Commands::Init(cmd)) => cmd.run().await,
        Some(Commands::Install(cmd)) => cmd.run().await,
        None => {
            // Check for iris-agentic-dev-* plugin on PATH before giving up
            let args: Vec<String> = std::env::args().collect();
            if args.len() > 1 {
                cmd::plugin::try_dispatch_plugin(&args[1], &args[2..])?;
            }
            eprintln!("Run `iris-agentic-dev --help` for usage.");
            std::process::exit(1);
        }
    }
}

//! Elicitation state management for MCP source control dialogs.
//! Stores pending elicitations keyed by UUID, expires after 5 minutes.

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use uuid::Uuid;

const EXPIRY: Duration = Duration::from_secs(300); // 5 minutes

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum ElicitationAction {
    /// Resume a iris_doc(mode=put) write
    Put,
    /// Resume an iris_source_control execute action
    ScmExecute,
}

/// Serde-friendly mirror of [`PendingElicitation`] without the non-serializable [`Instant`].
/// Used for serialization, deserialization, and persistence of elicitation state.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct PendingElicitationRecord {
    pub id: String,
    pub document: String,
    pub action: ElicitationAction,
    pub content: Option<String>,
    pub scm_action_id: Option<String>,
    pub namespace: String,
}

#[derive(Debug, Clone)]
pub struct PendingElicitation {
    pub id: String,
    pub document: String,
    pub action: ElicitationAction,
    /// Document content to write on resume (Put only)
    pub content: Option<String>,
    /// SCM action id to execute on resume (ScmExecute only)
    pub scm_action_id: Option<String>,
    pub namespace: String,
    pub expires_at: Instant,
}

#[derive(Clone, Default)]
pub struct ElicitationStore(Arc<Mutex<HashMap<String, PendingElicitation>>>);

impl ElicitationStore {
    pub fn new() -> Self {
        Self::default()
    }

    /// Insert a new pending elicitation and return its UUID.
    pub fn insert(
        &self,
        document: impl Into<String>,
        action: ElicitationAction,
        content: Option<String>,
        scm_action_id: Option<String>,
        namespace: impl Into<String>,
    ) -> String {
        let id = Uuid::new_v4().to_string();
        let entry = PendingElicitation {
            id: id.clone(),
            document: document.into(),
            action,
            content,
            scm_action_id,
            namespace: namespace.into(),
            expires_at: Instant::now() + EXPIRY,
        };
        self.0.lock().unwrap().insert(id.clone(), entry);
        id
    }

    /// Look up a pending elicitation by id. Returns None if expired or missing.
    pub fn lookup(&self, id: &str) -> Option<PendingElicitation> {
        let mut store = self.0.lock().unwrap();
        let entry = store.get(id)?;
        if Instant::now() > entry.expires_at {
            store.remove(id);
            return None;
        }
        Some(entry.clone())
    }

    /// Remove a pending elicitation.
    pub fn clear(&self, id: &str) {
        self.0.lock().unwrap().remove(id);
    }

    /// Remove all expired entries. Returns the count of removed entries.
    pub fn sweep(&self) -> usize {
        let mut store = self.0.lock().unwrap();
        let now = std::time::Instant::now();
        let expired: Vec<String> = store
            .iter()
            .filter(|(_, e)| now > e.expires_at)
            .map(|(k, _)| k.clone())
            .collect();
        let count = expired.len();
        for key in expired {
            store.remove(&key);
        }
        count
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_insert_returns_uuid() {
        let store = ElicitationStore::new();
        let id = store.insert("Foo.cls", ElicitationAction::Put, None, None, "USER");
        assert!(!id.is_empty());
    }

    #[test]
    fn test_lookup_finds_inserted() {
        let store = ElicitationStore::new();
        let id = store.insert(
            "Foo.cls",
            ElicitationAction::Put,
            Some("content".into()),
            None,
            "USER",
        );
        let pending = store.lookup(&id).expect("should find it");
        assert_eq!(pending.document, "Foo.cls");
        assert_eq!(pending.namespace, "USER");
        assert_eq!(pending.content.as_deref(), Some("content"));
    }

    #[test]
    fn test_lookup_missing_returns_none() {
        let store = ElicitationStore::new();
        assert!(store.lookup("nonexistent-id").is_none());
    }

    #[test]
    fn test_clear_removes_entry() {
        let store = ElicitationStore::new();
        let id = store.insert(
            "Bar.cls",
            ElicitationAction::ScmExecute,
            None,
            Some("CheckOut".into()),
            "USER",
        );
        store.clear(&id);
        assert!(store.lookup(&id).is_none());
    }

    #[test]
    fn test_sweep_empty_store() {
        let store = ElicitationStore::new();
        assert_eq!(store.sweep(), 0);
    }

    #[test]
    fn test_sweep_removes_nothing_fresh() {
        let store = ElicitationStore::new();
        store.insert("A.cls", ElicitationAction::Put, None, None, "USER");
        store.insert("B.cls", ElicitationAction::Put, None, None, "USER");
        assert_eq!(store.sweep(), 0, "fresh entries should not be swept");
    }

    #[test]
    fn test_scm_execute_action_fields() {
        let store = ElicitationStore::new();
        let id = store.insert(
            "App.cls",
            ElicitationAction::ScmExecute,
            None,
            Some("CheckIn".into()),
            "MYNS",
        );
        let p = store.lookup(&id).unwrap();
        assert!(matches!(p.action, ElicitationAction::ScmExecute));
        assert_eq!(p.scm_action_id.as_deref(), Some("CheckIn"));
        assert_eq!(p.namespace, "MYNS");
    }

