            let parts: Vec<&str> = out.splitn(4, '|').collect();
            if parts.len() < 4 {
                return err_json("INTEROP_ERROR", "unexpected response from IRIS");
            }
            ok_json(serde_json::json!({
                "success": true,
                "path": path,
                "namespace": parts[0],
                "dispatch_class": parts[1],
                "enabled": parts[2] != "0",
