//! iris_search — full-text search via Atelier REST v2 with sync→async fallback.

use crate::iris::connection::IrisConnection;
use crate::tools::log_store;
use schemars::JsonSchema;
use serde::Deserialize;
use std::sync::{Arc, Mutex};

#[derive(Debug, Deserialize, JsonSchema)]
pub struct SearchParams {
    pub query: String,
    #[serde(default)]
    pub regex: bool,
    #[serde(default)]
    pub case_sensitive: bool,
    /// Filter to document category: CLS, MAC, INT, INC, or ALL (default)
    pub category: Option<String>,
    /// Wildcard document scopes e.g. ["HS.FHIR.*.cls"]
    #[serde(default)]
    pub documents: Vec<String>,
    #[serde(default = "default_namespace")]
    pub namespace: String,
    /// If true, bypass the log store and return all results inline regardless of count.
    #[serde(default)]
    pub inline: bool,
}

fn default_namespace() -> String {
    "USER".to_string()
}

fn ok_json(v: serde_json::Value) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    Ok(rmcp::model::CallToolResult::success(vec![
        rmcp::model::Content::text(v.to_string()),
    ]))
}

pub async fn handle_iris_search(
    iris: &IrisConnection,
    client: &reqwest::Client,
    p: SearchParams,
    log_store: Arc<Mutex<log_store::LogStore>>,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    let category = p.category.as_deref().unwrap_or("ALL");
    let mut query_string = format!(
        "query={}&regex={}&sys=false&category={}",
        urlencoding::encode(&p.query),
        p.regex,
        category,
    );
    if p.case_sensitive {
        query_string.push_str("&case=1");
    }

    let sync_url = iris.versioned_ns_url(&p.namespace, &format!("/action/search?{}", query_string));

    // Try sync search with 2s timeout
    let sync_client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(2))
        .danger_accept_invalid_certs(true)
        .build()
        .unwrap_or_else(|_| client.clone());

    let sync_result = sync_client
        .get(&sync_url)
        .basic_auth(&iris.username, Some(&iris.password))
        .send()
        .await;

    match sync_result {
        Ok(resp) if resp.status().is_success() => {
            let body: serde_json::Value = resp.json().await.unwrap_or_default();
            // If we got a workId, it's async — fall through to polling
            if body["result"]["workId"].is_null() {
                return parse_search_results(body, &p.query, p.inline, &log_store);
            }
            let work_id = body["result"]["workId"].as_str().unwrap_or("").to_string();
            poll_async_search(
                iris,
                client,
                &work_id,
                &p.namespace,
                &p.query,
                p.inline,
                &log_store,
            )
            .await
        }
        _ => {
            // Timeout or error — fall back to async POST
            let post_url = iris.versioned_ns_url(&p.namespace, "/action/search");
            let post_body = serde_json::json!({
                "query": p.query,
                "regex": p.regex,
                "sys": false,
                "category": category,
            });
            let resp = client
                .post(&post_url)
                .basic_auth(&iris.username, Some(&iris.password))
                .json(&post_body)
                .send()
                .await
                .map_err(|e| {
                    rmcp::ErrorData::internal_error(format!("Search request failed: {e}"), None)
                })?;

            let body: serde_json::Value = resp.json().await.unwrap_or_default();
            if let Some(work_id) = body["result"]["workId"].as_str() {
                poll_async_search(
                    iris,
                    client,
                    work_id,
                    &p.namespace,
                    &p.query,
                    p.inline,
                    &log_store,
                )
                .await
            } else {
                parse_search_results(body, &p.query, p.inline, &log_store)
            }
        }
    }
}

async fn poll_async_search(
    iris: &IrisConnection,
    client: &reqwest::Client,
    work_id: &str,
    namespace: &str,
    query: &str,
    inline: bool,
    log_store: &Arc<Mutex<log_store::LogStore>>,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    let poll_url = iris.versioned_ns_url(
        namespace,
        &format!("/action/search?workId={}", urlencoding::encode(work_id)),
    );

    let deadline = std::time::Instant::now() + std::time::Duration::from_secs(300);
    loop {
        tokio::time::sleep(std::time::Duration::from_secs(2)).await;

        if std::time::Instant::now() > deadline {
            return ok_json(serde_json::json!({
                "success": false,
                "error_code": "SEARCH_TIMEOUT",
                "error": "Async search did not complete within 5 minutes",
                "query": query,
            }));
        }

        let resp = client
            .get(&poll_url)
            .basic_auth(&iris.username, Some(&iris.password))
            .send()
            .await;

        match resp {
            Ok(r) if r.status().is_success() => {
                let body: serde_json::Value = r.json().await.unwrap_or_default();
                if body["result"]["workId"].is_null() {
                    return parse_search_results(body, query, inline, log_store);
                }
                // Still pending — keep polling
            }
            _ => continue,
        }
    }
}

fn parse_search_results(
    body: serde_json::Value,
    query: &str,
    inline: bool,
    log_store: &Arc<Mutex<log_store::LogStore>>,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    let content = body["result"]["content"]
        .as_array()
        .cloned()
        .unwrap_or_default();
    let total = content.len();
    let results: Vec<serde_json::Value> = content
        .into_iter()
        .map(|item| {
            serde_json::json!({
                "document": item["doc"],
                "line": item["atLine"],
                "member": item["member"],
                "content": item["text"],
            })
        })
        .collect();

    let mut resp = serde_json::json!({
        "success": true,
        "query": query,
        "results": results,
        "total_found": total,
    });

    // Progressive disclosure (027): truncate results when count exceeds threshold.
    let threshold = log_store::read_inline_threshold("IRIS_INLINE_SEARCH", 30);
    log_store::apply_truncation(
        &mut resp,
        "results",
        threshold,
        inline,
        log_store,
        "iris_search",
    );

    ok_json(resp)
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── SearchParams serde ────────────────────────────────────────────────────
    #[test]
    fn test_search_params_minimal() {
        let p: SearchParams =
            serde_json::from_str(r#"{"query":"test","namespace":"USER"}"#).unwrap();
        assert_eq!(p.query, "test");
    }

    #[test]
    fn test_search_params_namespace_required_field() {
        let result: Result<SearchParams, _> =
            serde_json::from_str(r#"{"query":"x","namespace":"MYNS"}"#);
        assert!(result.is_ok());
        assert_eq!(result.unwrap().namespace, "MYNS");
    }

    #[test]
    fn test_search_params_defaults() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "Ens.*"}"#).unwrap();
        assert_eq!(p.namespace, "USER");
        assert!(!p.regex);
        assert!(!p.case_sensitive);
        assert!(p.category.is_none());
        assert!(p.documents.is_empty());
        assert!(!p.inline);
    }

    #[test]
    fn test_search_params_with_category() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x", "category": "CLS"}"#).unwrap();
        assert_eq!(p.category.as_deref(), Some("CLS"));
    }

    #[test]
    fn test_search_params_regex_flag() {
        let p: SearchParams =
            serde_json::from_str(r#"{"query": "Ens\\..*", "regex": true}"#).unwrap();
        assert!(p.regex);
    }

    #[test]
    fn test_search_params_documents_list() {
        let p: SearchParams =
            serde_json::from_str(r#"{"query": "x", "documents": ["Foo.*.cls", "Bar.*.cls"]}"#)
                .unwrap();
        assert_eq!(p.documents.len(), 2);
    }

    #[test]
    fn test_search_params_missing_query_fails() {
        let r: Result<SearchParams, _> = serde_json::from_str(r#"{}"#);
        assert!(r.is_err(), "query is required");
    }

    #[test]
    fn test_search_params_case_sensitive_flag() {
        let p: SearchParams =
            serde_json::from_str(r#"{"query": "Foo", "case_sensitive": true}"#).unwrap();
        assert!(p.case_sensitive);
    }

    #[test]
    fn test_search_params_inline_flag() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x", "inline": true}"#).unwrap();
        assert!(p.inline);
    }

    #[test]
    fn test_search_params_inline_default_false() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x"}"#).unwrap();
        assert!(!p.inline);
    }

    #[test]
    fn test_search_params_category_none_by_default() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x"}"#).unwrap();
        assert!(p.category.is_none());
    }

    #[test]
    fn test_search_params_category_all_variants() {
        for cat in &["CLS", "MAC", "INT", "INC", "ALL"] {
            let json = format!(r#"{{"query": "x", "category": "{}"}}"#, cat);
            let p: SearchParams = serde_json::from_str(&json).unwrap();
            assert_eq!(p.category.as_deref(), Some(*cat));
        }
    }

    #[test]
    fn test_search_params_documents_empty_by_default() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x"}"#).unwrap();
        assert!(p.documents.is_empty());
    }

    #[test]
    fn test_search_params_documents_single_entry() {
        let p: SearchParams =
            serde_json::from_str(r#"{"query": "x", "documents": ["Ens.Production.cls"]}"#).unwrap();
        assert_eq!(p.documents, vec!["Ens.Production.cls"]);
    }

    #[test]
    fn test_search_params_all_fields_set() {
        let json = r#"{
            "query": "FindMe",
            "regex": true,
            "case_sensitive": true,
            "category": "MAC",
            "documents": ["App.*.cls"],
            "namespace": "PROD",
            "inline": true
        }"#;
        let p: SearchParams = serde_json::from_str(json).unwrap();
        assert_eq!(p.query, "FindMe");
        assert!(p.regex);
        assert!(p.case_sensitive);
        assert_eq!(p.category.as_deref(), Some("MAC"));
        assert_eq!(p.documents, vec!["App.*.cls"]);
        assert_eq!(p.namespace, "PROD");
        assert!(p.inline);
    }

    #[test]
    fn test_search_params_empty_query_string_allowed() {
        // An empty string is technically valid JSON for the query field
        let p: SearchParams = serde_json::from_str(r#"{"query": ""}"#).unwrap();
        assert_eq!(p.query, "");
    }

    #[test]
    fn test_search_params_regex_default_false() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x"}"#).unwrap();
        assert!(!p.regex);
    }

    #[test]
    fn test_search_params_case_sensitive_default_false() {
        let p: SearchParams = serde_json::from_str(r#"{"query": "x"}"#).unwrap();
        assert!(!p.case_sensitive);
    }
}

//! skill, skill_community, kb, agent_info tools via docker exec + ^SKILLS global.

use crate::iris::connection::IrisConnection;
use crate::tools::ToolCallEntry;
use schemars::JsonSchema;
use serde::Deserialize;
use std::collections::VecDeque;

fn ok_json(v: serde_json::Value) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    Ok(rmcp::model::CallToolResult::success(vec![
        rmcp::model::Content::text(v.to_string()),
    ]))
}
fn err_json(code: &str, msg: &str) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    ok_json(serde_json::json!({"success": false, "error_code": code, "error": msg}))
}

fn learning_enabled() -> bool {
    std::env::var("OBJECTSCRIPT_LEARNING")
        .map(|v| v != "false")
        .unwrap_or(true)
}

pub fn skills_namespace() -> String {
    std::env::var("OBJECTSCRIPT_SKILLMCP_NAMESPACE").unwrap_or_else(|_| "USER".to_string())
}

async fn xecute(
    iris: &IrisConnection,
    _client: &reqwest::Client,
    code: &str,
    namespace: &str,
) -> anyhow::Result<String> {
    // /action/xecute does not exist in Atelier REST — use docker exec path
    iris.execute(code, namespace).await
}

// ── skill ─────────────────────────────────────────────────────────────────────

#[derive(Debug, Deserialize, JsonSchema)]
pub struct SkillParams {
    /// Action: list, describe, search, forget, propose
    pub action: String,
    pub name: Option<String>,
    pub query: Option<String>,
}

pub async fn handle_skill(
    iris: &IrisConnection,
    client: &reqwest::Client,
    p: SkillParams,
    history: &std::sync::Mutex<VecDeque<ToolCallEntry>>,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    if !learning_enabled() {
        return err_json(
            "LEARNING_DISABLED",
            "Set OBJECTSCRIPT_LEARNING=true to enable skills",
        );
    }

    let ns = skills_namespace();

    match p.action.as_str() {
        "list" => {
            // Bug 9: use separator variable so empty global yields "[]" not "]".
            let code = "set key=\"\" set out=\"[\" set sep=\"\" for  { set key=$order(^SKILLS(key)) quit:key=\"\"  set data=$get(^SKILLS(key)) set out=out_sep_\"{\"_\"\\\"name\\\":\\\"\"_key_\"\\\",\\\"description\\\":\\\"\"_$piece(data,\"|\",1)_\"\\\",\\\"usage_count\\\":\"_$piece(data,\"|\",3)_\"}\" set sep=\",\" } set out=out_\"]\" write out";
            let raw = xecute(iris, client, code, &ns).await.unwrap_or_default();
            let skills: serde_json::Value =
                serde_json::from_str(&raw).unwrap_or(serde_json::json!([]));
            ok_json(serde_json::json!({"success": true, "skills": skills}))
        }
        "describe" => {
            let name = p.name.as_deref().unwrap_or("");
            let code = format!(
                "set data=$get(^SKILLS(\"{}\")) write data",
                name.replace('"', "\\\"")
            );
            let raw = xecute(iris, client, &code, &ns).await.unwrap_or_default();
            if raw.is_empty() {
                return err_json("NOT_FOUND", &format!("Skill '{}' not found", name));
            }
            let parts: Vec<&str> = raw.splitn(4, '|').collect();
            ok_json(serde_json::json!({
                "success": true,
                "name": name,
                "description": parts.first().unwrap_or(&""),
                "body": parts.get(1).unwrap_or(&""),
                "usage_count": parts.get(2).unwrap_or(&"0"),
                "created_at": parts.get(3).unwrap_or(&""),
            }))
        }
        "search" => {
            let query = p.query.as_deref().unwrap_or("").to_lowercase();
            // Bug 9: use separator variable so empty results yield "[]" not "]".
            let code = format!(
                "set key=\"\" set out=\"[\" set sep=\"\" for {{ set key=$order(^SKILLS(key)) quit:key=\"\"  set data=$get(^SKILLS(key)) if $find($zconvert(key_data,\"L\"),\"{}\")>0 {{ set out=out_sep_\"{{\\\"name\\\":\\\"\"_key_\"\\\",\\\"description\\\":\\\"\"_$piece(data,\"|\",1)_\"\\\"}}\" set sep=\",\" }} }} set out=out_\"]\" write out",
                query.replace('"', "\\\"")
            );
            let raw = xecute(iris, client, &code, &ns).await.unwrap_or_default();
            let results: serde_json::Value =
                serde_json::from_str(&raw).unwrap_or(serde_json::json!([]));
            ok_json(serde_json::json!({"success": true, "query": query, "results": results}))
        }
        "forget" => {
            let name = p.name.as_deref().unwrap_or("");
            let code = format!(
                "kill ^SKILLS(\"{}\") write \"ok\"",
                name.replace('"', "\\\"")
            );
            xecute(iris, client, &code, &ns).await.unwrap_or_default();
            ok_json(serde_json::json!({"success": true, "name": name, "action": "forgotten"}))
        }
        "propose" => {
            let calls: Vec<String> = {
                let h = history.lock().unwrap();
                if h.len() < 5 {
                    return err_json(
                        "INSUFFICIENT_HISTORY",
                        &format!(
                            "Need at least 5 tool calls to propose a skill, have {}",
                            h.len()
                        ),
                    );
                }
                h.iter().rev().take(20).map(|c| c.tool.clone()).collect()
            };
            // Synthesize skill name from most frequent tool
            let mut freq = std::collections::HashMap::new();
            for t in &calls {
                *freq.entry(t.as_str()).or_insert(0u32) += 1;
            }
            let top = freq
                .iter()
                .max_by_key(|e| e.1)
                .map(|e| *e.0)
                .unwrap_or("workflow");
            let skill_name = format!("auto-{}-{}", top, chrono::Utc::now().timestamp() % 10000);
            let description = format!(
                "Auto-synthesized from recent tool calls: {}",
                calls.join(", ")
            );
            let body = format!(
                "Recent workflow: {}",
                calls
                    .iter()
                    .take(5)
                    .cloned()
                    .collect::<Vec<_>>()
                    .join(" → ")
            );
            let now = chrono::Utc::now().format("%Y-%m-%dT%H:%M:%SZ").to_string();
            let code = format!(
                "set ^SKILLS(\"{}\")=\"{}|{}|0|{}\" write \"ok\"",
                skill_name.replace('"', "\\\""),
                description.replace('"', "\\\""),
                body.replace('"', "\\\""),
                now,
            );
            xecute(iris, client, &code, &ns).await.unwrap_or_default();
            ok_json(serde_json::json!({
                "success": true,
                "skill": {"name": skill_name, "description": description, "body": body}
            }))
        }
        other => err_json(
            "INVALID_PARAM",
            &format!(
                "Unknown action='{}'. Use: list, describe, search, forget, propose",
                other
            ),
        ),
    }
}

// ── skill_community ───────────────────────────────────────────────────────────

#[derive(Debug, Deserialize, JsonSchema)]
pub struct SkillCommunityParams {
    /// Action: list or install
    pub action: String,
    pub package: Option<String>,
}

pub async fn handle_skill_community(
    iris: &IrisConnection,
    client: &reqwest::Client,
    p: SkillCommunityParams,
    registry: &crate::skills::SkillRegistry,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    if !learning_enabled() {
        return err_json(
            "LEARNING_DISABLED",
            "Set OBJECTSCRIPT_LEARNING=true to enable community skills",
        );
    }

    match p.action.as_str() {
        "list" => {
            let items: Vec<serde_json::Value> = registry
                .list_skills()
                .iter()
                .map(|s| serde_json::json!({"name": s.name, "description": s.description}))
                .collect();
            ok_json(serde_json::json!({"success": true, "skills": items}))
        }
        "install" => {
            let pkg = p.package.as_deref().unwrap_or("");
            if pkg.is_empty() {
                return err_json("INVALID_PARAM", "package name required for action=install");
            }
            let skill_opt = registry
                .list_skills()
                .iter()
                .find(|s| s.name == pkg)
                .map(|s| (s.name.clone(), s.description.clone(), s.content.clone()));
            match skill_opt {
                Some((sname, sdesc, scontent)) => {
                    let ns = skills_namespace();
                    let now = chrono::Utc::now().format("%Y-%m-%dT%H:%M:%SZ").to_string();
                    let code = format!(
                        "set ^SKILLS(\"{}\")=\"{}|{}|0|{}\" write \"ok\"",
                        sname.replace('"', "\\\""),
                        sdesc.replace('"', "\\\""),
                        scontent.replace('"', "\\\""),
                        now,
                    );
                    xecute(iris, client, &code, &ns).await.unwrap_or_default();
                    ok_json(serde_json::json!({"success": true, "installed": sname}))
                }
                None => err_json("NOT_FOUND", &format!("Community skill '{}' not found", pkg)),
            }
        }
        other => err_json(
            "INVALID_PARAM",
            &format!("Unknown action='{}'. Use: list, install", other),
        ),
    }
}

// ── kb ────────────────────────────────────────────────────────────────────────

#[derive(Debug, Deserialize, JsonSchema)]
pub struct KbParams {
    /// Action: index or recall
    pub action: String,
    /// File path for index, query for recall
    pub path: Option<String>,
    pub query: Option<String>,
    #[serde(default = "default_top_k")]
    pub top_k: usize,
}

fn default_top_k() -> usize {
    5
}

pub async fn handle_kb(
    iris: &IrisConnection,
    client: &reqwest::Client,
    p: KbParams,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    if !learning_enabled() {
        return err_json(
            "LEARNING_DISABLED",
            "Set OBJECTSCRIPT_LEARNING=true to enable KB",
        );
    }

    let ns = skills_namespace();

    match p.action.as_str() {
        "index" => {
            let path = p.path.as_deref().unwrap_or(".");
            let workspace =
                std::env::var("OBJECTSCRIPT_WORKSPACE").unwrap_or_else(|_| ".".to_string());
            let base = if path == "." {
                workspace.as_str()
            } else {
                path
            };

            let mut indexed = 0usize;
            if let Ok(entries) = std::fs::read_dir(base) {
                for entry in entries.flatten() {
                    let fp = entry.path();
                    if fp
                        .extension()
                        .and_then(|e| e.to_str())
                        .map(|e| e == "md" || e == "txt")
                        .unwrap_or(false)
                    {
                        if let Ok(content) = std::fs::read_to_string(&fp) {
                            let fname = fp
                                .file_name()
                                .and_then(|n| n.to_str())
                                .unwrap_or("")
                                .replace('"', "\\\"");
                            let chunk: String = content.chars().take(2000).collect();
                            let chunk_escaped = chunk.replace('"', "\\\"").replace('\n', "\\n");
                            let code = format!(
                                "set ^KBCHUNKS(\"{fname}\")=\"{chunk_escaped}\" write \"ok\""
                            );
                            xecute(iris, client, &code, &ns).await.unwrap_or_default();
                            indexed += 1;
                        }
                    }
                }
            }
            ok_json(serde_json::json!({"success": true, "indexed": indexed, "path": base}))
        }
        "recall" => {
            let query = p.query.as_deref().unwrap_or("").to_lowercase();
            let top_k = p.top_k;
            // Bug 9: use separator variable so empty results yield "[]" not "]".
            let code = format!(
                "set key=\"\" set out=\"[\" set sep=\"\" set count=0 for {{ set key=$order(^KBCHUNKS(key)) quit:(key=\"\" || count>={top_k})  set data=$get(^KBCHUNKS(key)) if $find($zconvert(data,\"L\"),\"{query}\")>0 {{ set out=out_sep_\"{{\\\"file\\\":\\\"\"_key_\"\\\",\\\"excerpt\\\":\\\"\"_$extract(data,1,200)_\"\\\"}}\" set sep=\",\" set count=count+1 }} }} set out=out_\"]\" write out",
                query = query.replace('"', "\\\""),
                top_k = top_k,
            );
            let raw = xecute(iris, client, &code, &ns).await.unwrap_or_default();
            let results: serde_json::Value =
                serde_json::from_str(&raw).unwrap_or(serde_json::json!([]));
            ok_json(serde_json::json!({"success": true, "query": query, "results": results}))
        }
        other => err_json(
            "INVALID_PARAM",
            &format!("Unknown action='{}'. Use: index, recall", other),
        ),
    }
}

// ── agent_info ────────────────────────────────────────────────────────────────

#[derive(Debug, Deserialize, JsonSchema)]
pub struct AgentInfoParams {
    /// What to return: stats or history
    pub what: String,
    #[serde(default = "default_limit")]
    pub limit: usize,
}

fn default_limit() -> usize {
    20
}

pub async fn handle_agent_info(
    iris: &IrisConnection,
    client: &reqwest::Client,
    p: AgentInfoParams,
    history: &std::sync::Mutex<VecDeque<ToolCallEntry>>,
) -> Result<rmcp::model::CallToolResult, rmcp::ErrorData> {
    match p.what.as_str() {
        "stats" => {
            let ns = skills_namespace();
            let code = "set count=0 set key=\"\" for { set key=$order(^SKILLS(key)) quit:key=\"\"  set count=count+1 } write count";
            let skill_count: usize = xecute(iris, client, code, &ns)
                .await
                .unwrap_or_default()
                .trim()
                .parse()
                .unwrap_or(0);
            let session_calls = history.lock().map(|h| h.len()).unwrap_or(0);
            ok_json(serde_json::json!({
                "success": true,
                "skill_count": skill_count,
                "session_calls": session_calls,
                "learning_enabled": learning_enabled(),
            }))
        }
        "history" => {
            let limit = p.limit;
            let calls: Vec<serde_json::Value> = history
                .lock()
                .map(|h| {
                    h.iter()
                        .rev()
                        .take(limit)
                        .map(|c| {
                            serde_json::json!({
                                "tool": c.tool,
                                "success": c.success,
                                "ago_secs": c.timestamp.elapsed().as_secs(),
                            })
                        })
                        .collect()
                })
                .unwrap_or_default();
            ok_json(serde_json::json!({"success": true, "calls": calls}))
        }
        other => err_json(
            "INVALID_PARAM",
            &format!("Unknown what='{}'. Use: stats, history", other),
        ),
    }
}

